import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, Info, BookOpen, AlertCircle, 
  BarChart3, ArrowLeft, Flag, ListChecks, Activity,
  ImageIcon, Filter, Save
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onAddMistake?: (id: string) => void; 
  onRemoveMistake?: (id: string) => void; 
}

const Quiz: React.FC<QuizProps> = ({ 
    data, 
    toggleHeader, 
    onExit, 
    onImageClick,
    mistakes = [], 
    onAddMistake, 
    onRemoveMistake 
}) => {
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Professional Notification State
  const [notification, setNotification] = useState<{show: boolean, type: 'add' | 'remove'}>({ show: false, type: 'add' });

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [onlyDiagrams, setOnlyDiagrams] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  // --- PERSISTENCE LOGIC ---
  useEffect(() => {
    const savedState = localStorage.getItem('ot_quiz_active_session');
    if (savedState) {
        try {
            const parsed = JSON.parse(savedState);
            // Only resume if we have valid data and we are in config mode
            if (view === 'config' && parsed.questions && parsed.questions.length > 0) {
                // Check if user wants to resume (simple logic: just resume)
                setQuestions(parsed.questions);
                setCurrentQIndex(parsed.currentQIndex);
                setTimeLeft(parsed.timeLeft);
                setMode(parsed.mode);
                setView(parsed.view);
                if (toggleHeader) toggleHeader(false);
            }
        } catch (e) {
            console.error("Failed to restore quiz session", e);
            localStorage.removeItem('ot_quiz_active_session');
        }
    }
  }, []);

  // Save state on every change
  useEffect(() => {
    if (view === 'playing' || view === 'summary') {
        const stateToSave = {
            questions,
            currentQIndex,
            timeLeft,
            mode,
            view
        };
        localStorage.setItem('ot_quiz_active_session', JSON.stringify(stateToSave));
    } else if (view === 'results' || view === 'config') {
        localStorage.removeItem('ot_quiz_active_session');
    }
  }, [questions, currentQIndex, timeLeft, mode, view]);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakes.includes(q.id));
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      if (onlyDiagrams) {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      return pool;
  }, [mode, mistakes, selectedCategories, data, onlyDiagrams]);

  const currentPoolSize = currentPool.length;

  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Smart Review is empty! Great job mastering the content.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    localStorage.removeItem('ot_quiz_active_session');
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  // --- IMMEDIATE MISTAKE SYSTEM LOGIC ---
  const handleOptionSelect = (option: string) => {
      const currentQ = questions[currentQIndex];

      // If already answered in Study/Vault mode, ignore click
      if ((mode === 'study' || mode === 'vault') && currentQ.userAnswer) return;

      const isCorrect = option === currentQ.correctOption;

      // 1. Update Local State
      setQuestions(prev => { 
          const c = [...prev]; 
          c[currentQIndex].userAnswer = option; 
          return c; 
      });

      // 2. Immediate Smart Review Update
      if (!isCorrect) {
          // If wrong, add to mistakes immediately
          onAddMistake?.(currentQ.id);

          // Show "Added" Notification
          setNotification({ show: true, type: 'add' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      } 
      else if (isCorrect && mode === 'vault') {
          // If correct AND we are in Review Mode, remove it
          onRemoveMistake?.(currentQ.id);

          // Show "Removed/Mastered" Notification
          setNotification({ show: true, type: 'remove' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      }
  };

  const handleFinish = () => {
    cancel();
    localStorage.removeItem('ot_quiz_active_session');

    // AUTOMATICALLY ADD UNANSWERED OR WRONG QUESTIONS TO MISTAKES
    questions.forEach(q => {
        const isWrongOrSkipped = q.userAnswer !== q.correctOption;
        if (isWrongOrSkipped) {
            onAddMistake?.(q.id);
        }
    });

    setView('results');
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  // --- FILTER OPTIONS FOR MODAL ---
  const quizFilterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Questions',
        icon: ImageIcon,
        isActive: onlyDiagrams,
        onClick: () => setOnlyDiagrams(!onlyDiagrams),
        colorTheme: 'rose'
    }
  ];

  // --- VIEW: CONFIGURATION ---
  if (view === 'config') {
    const filtersActive = selectedCategories.length > 0 || onlyDiagrams;

    return (
      <div className="h-full w-full flex items-center justify-center p-4 bg-slate-50/50 pb-32 md:pb-4">
          {/* Reduced max-height for mobile to 65vh to prevent button cutoff by bottom navigation/safe area */}
          <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[65vh] md:max-h-[90vh]">
            <div className="bg-slate-900 p-6 md:p-8 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl md:text-3xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-rose-500 text-xs font-bold uppercase tracking-[0.2em] mt-1">Anatomy and Physiology OT</p>
                </div>
                <div className="absolute right-0 top-0 w-64 h-64 bg-rose-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="flex-1 p-6 md:p-8 space-y-4 overflow-y-auto custom-scrollbar">
                {/* Responsive Grid for Mode Buttons */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>Exam</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Strict Timing</p>
                    </button>

                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Instant Feedback</p>
                    </button>

                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'vault' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'vault' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={18} />
                        </div>
                        <div className="flex justify-between items-center">
                            <h3 className={`font-bold text-sm ${mode === 'vault' ? 'text-rose-900' : 'text-slate-900'}`}>Smart Review</h3>
                            {mistakes.length > 0 && <span className="bg-rose-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">{mistakes.length}</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Fix Mistakes</p>
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className={`p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${filtersActive ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-slate-50 hover:bg-white hover:border-slate-200'}`}
                    >
                        <div className="flex items-center gap-3 overflow-hidden">
                            <div className={`p-2 rounded-lg ${filtersActive ? 'bg-rose-100 text-rose-600' : 'bg-white border border-slate-200 text-slate-400 group-hover:text-rose-500'}`}>
                                <Filter size={16}/>
                            </div>
                            <div className="flex flex-col text-left min-w-0">
                                <span className={`text-[10px] font-black uppercase tracking-wider ${filtersActive ? 'text-rose-400' : 'text-slate-400'}`}>Filters</span>
                                <span className={`font-bold text-xs truncate ${filtersActive ? 'text-rose-900' : 'text-slate-700'}`}>
                                    {selectedCategories.length > 0 ? `${selectedCategories.length} Chapters` : onlyDiagrams ? 'Diagrams Only' : 'Default Pool'}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className={`${filtersActive ? 'text-rose-400' : 'text-slate-400'} group-hover:translate-x-1 transition-transform shrink-0`} />
                    </button>

                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 flex flex-col justify-center gap-2">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Question Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit}</span>
                        </div>
                        <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                        />
                    </div>
                </div>
            </div>

            <div className="p-4 md:p-6 border-t border-slate-100 bg-white shrink-0">
                <button 
                    onClick={startSession}
                    disabled={currentPoolSize === 0}
                    className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    Start Exam <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setOnlyDiagrams(false); }}
            mainOptions={quizFilterOptions}
            title="Exam Settings"
          />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isStudy = mode === 'study' || mode === 'vault'; 
    const showFeedback = isStudy && currentQ.userAnswer; 

    return (
      <div className="h-full flex flex-col bg-white relative">

        {/* --- PROFESSIONAL NOTIFICATION --- */}
        {notification.show && (
            <div className="absolute top-20 left-0 right-0 flex justify-center z-50 pointer-events-none animate-in fade-in slide-in-from-top-4">
                <div className={`px-6 py-3 rounded-full shadow-2xl border-2 flex items-center gap-3 font-bold text-xs uppercase tracking-widest ${
                    notification.type === 'add' 
                    ? 'bg-rose-500 text-white border-white' 
                    : 'bg-emerald-500 text-white border-white'
                }`}>
                    {notification.type === 'add' ? (
                        <>
                            <AlertTriangle size={16} className="fill-current text-white" />
                            <span>Added to Smart Review</span>
                        </>
                    ) : (
                        <>
                            <CheckCircle2 size={16} className="fill-current text-white" />
                            <span>Mastered & Removed</span>
                        </>
                    )}
                </div>
            </div>
        )}

        <header className="h-14 md:h-16 glass border-b border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 text-white rounded-lg md:rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
                <div>
                    <h1 className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none hidden md:block">
                        {isExam ? 'Assessment' : 'Study'}
                    </h1>
                    <p className="text-xs font-bold text-slate-900 truncate max-w-[120px] md:max-w-none">Anatomy and Physiology OT</p>
                </div>
            </div>
            <div className="flex items-center gap-2 md:gap-3">

                {/* NEW: Immediate Submit Button */}
                <button 
                    onClick={goToSummary}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-slate-200 text-slate-600 rounded-lg md:rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider hover:bg-slate-50 hover:text-slate-900 transition-all shadow-sm"
                    title="Finish Exam Immediately"
                >
                    <ListChecks size={16} className="text-emerald-500" />
                    <span className="hidden sm:inline">Submit</span>
                </button>

                {isExam && (
                    <div className="px-3 py-1.5 md:px-4 md:py-2 bg-rose-50 text-rose-600 rounded-lg md:rounded-xl font-mono font-bold text-xs md:text-sm border border-rose-100 flex items-center gap-2">
                        <Clock size={14} />
                        {formatTime(timeLeft)}
                    </div>
                )}

                <button 
                    onClick={(e) => toggleFlag(currentQIndex, e)}
                    className={`p-2 rounded-lg md:rounded-xl border transition-all ${currentQ.isFlagged ? 'bg-rose-100 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400'}`}
                >
                    <Flag size={16} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                </button>

                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-slate-50 rounded-lg md:rounded-xl text-slate-400 border border-slate-100"><LayoutGrid size={16} /></button>
            </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={scrollRef}>
            <div className="max-w-3xl mx-auto space-y-6 md:space-y-8 pb-20">
                <div className="space-y-4 md:space-y-6">
                    <div className="flex flex-wrap gap-2">
                        <span className="px-2 py-1 bg-slate-100 text-[9px] md:text-[10px] font-black uppercase text-slate-500 rounded-md border border-slate-200">{currentQ.data.category.split(':')[0]}</span>
                        {currentQ.isFlagged && <div className="flex items-center gap-1 text-[9px] font-bold text-rose-600 bg-rose-50 px-2 py-1 rounded border border-rose-100"><Flag size={10} fill="currentColor"/> FLAGGED</div>}
                    </div>

                    <h2 className="text-lg md:text-2xl font-bold text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                    {currentQ.data.questionImage && (
                        <div className="rounded-2xl border border-slate-100 bg-slate-50 p-2 overflow-hidden cursor-zoom-in" onClick={() => onImageClick?.(currentQ.data.questionImage!)}>
                            <img src={cleanImageUrl(currentQ.data.questionImage)} className="w-full max-h-[300px] object-contain rounded-xl" alt="Diagram" />
                        </div>
                    )}

                    <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;

                            let containerClass = "border-slate-200 hover:bg-slate-50";
                            let iconClass = "bg-slate-100 text-slate-500";
                            let iconContent = <span className="text-xs">{String.fromCharCode(65 + i)}</span>;

                            if (isExam) {
                                if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50 ring-1 ring-slate-900 shadow-md";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            } else {
                                if (showFeedback) {
                                    const isCorrect = opt === currentQ.correctOption;
                                    const isWrong = isSelected && !isCorrect;

                                    if (isCorrect) {
                                        containerClass = "border-emerald-500 bg-emerald-50/50";
                                        iconClass = "bg-emerald-500 text-white";
                                        iconContent = <Check size={14} />;
                                    } else if (isWrong) {
                                        containerClass = "border-rose-500 bg-rose-50/50";
                                        iconClass = "bg-rose-500 text-white";
                                        iconContent = <X size={14} />;
                                    } else {
                                        containerClass = "opacity-50 border-slate-100";
                                    }
                                } else if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            }

                            return (
                                <button 
                                    key={i} 
                                    onClick={() => handleOptionSelect(opt)} 
                                    className={`w-full p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 text-left group min-h-[60px] ${containerClass}`}
                                >
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold shrink-0 transition-colors ${iconClass}`}>
                                        {iconContent}
                                    </div>
                                    <span className="font-medium text-sm md:text-base text-slate-800" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                    </div>
                </div>

                {showFeedback && (
                    <div className="p-6 md:p-8 bg-slate-900 text-white rounded-[2rem] space-y-4 animate-in slide-in-from-bottom-2 duration-500 shadow-2xl ring-4 ring-slate-100 relative overflow-hidden">
                        {/* Decorative Gradient Background */}
                        <div className="absolute top-0 right-0 w-64 h-64 bg-rose-500/10 rounded-full blur-3xl -mr-20 -mt-20 pointer-events-none"></div>

                        <div className="flex items-center justify-between relative z-10 border-b border-white/10 pb-4">
                            <div className="flex items-center gap-3 text-rose-400">
                                <div className="p-2 bg-rose-500/20 rounded-lg">
                                    <Info size={20} />
                                </div>
                                <div>
                                    <h4 className="font-black uppercase text-[11px] tracking-[0.2em] text-white">Clinical Rationale</h4>
                                    <span className="text-[10px] text-rose-300 font-bold">Expert Explanation</span>
                                </div>
                            </div>
                            {currentQ.userAnswer !== currentQ.correctOption && (
                                <div className="flex items-center gap-1.5 px-3 py-1.5 bg-rose-500 text-white rounded-lg text-[10px] font-black uppercase tracking-widest shadow-lg shadow-rose-900/20">
                                    <AlertTriangle size={12} className="fill-current" /> Review Added
                                </div>
                            )}
                        </div>

                        <div className="relative z-10 prose prose-invert max-w-none">
                            <p className="text-sm md:text-base text-slate-300 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct identification based on standard anatomical terminology." }} />
                        </div>
                    </div>
                )}
            </div>
        </div>

        <footer className="h-20 border-t border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 bg-white/95 backdrop-blur z-30 fixed bottom-0 left-0 right-0 md:relative">
            <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="px-4 py-2 rounded-lg font-black text-[10px] uppercase tracking-widest text-slate-400 disabled:opacity-20 flex items-center gap-2 transition-all hover:text-slate-900"><ChevronLeft size={16}/> Back</button>

            {currentQIndex === questions.length - 1 ? (
                <button 
                    onClick={goToSummary} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Submit Exam <ListChecks size={16} />
                </button>
            ) : (
                <button 
                    onClick={() => setCurrentQIndex(c => c + 1)} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Next <ChevronRight size={16} />
                </button>
            )}
        </footer>

        {isSidebarOpen && (
            <div className="fixed inset-0 z-50 flex justify-end">
                <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
                <div className="w-80 h-full bg-white shadow-2xl relative z-10 p-6 flex flex-col animate-in slide-in-from-right duration-300">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest">Question Map</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="p-2 bg-slate-50 rounded-lg text-slate-400 hover:text-slate-900"><X size={16} /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-2 content-start custom-scrollbar p-1">
                        {questions.map((q, i) => (
                            <button 
                                key={i} 
                                onClick={() => { setCurrentQIndex(i); setIsSidebarOpen(false); }} 
                                className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                    currentQIndex === i 
                                        ? 'bg-slate-900 border-slate-900 text-white' 
                                        : q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-600'
                                            : 'bg-slate-50 border-slate-100 text-slate-300'
                                }`}
                            >
                                {i + 1}
                                {q.isFlagged && (
                                    <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-rose-500 rounded-full border-2 border-white"></div>
                                )}
                            </button>
                        ))}
                    </div>
                </div>
            </div>
        )}
      </div>
    );
  }

  // --- VIEW: SUMMARY ---
  if (view === 'summary') {
      const answeredCount = questions.filter(q => q.userAnswer).length;
      const flaggedCount = questions.filter(q => q.isFlagged).length;
      const unansweredCount = questions.length - answeredCount;

      return (
          <div className="h-full w-full bg-slate-50 flex flex-col">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
                  <div>
                      <h2 className="text-lg font-black text-slate-900 tracking-tight">Summary</h2>
                  </div>
                  {mode === 'exam' && (
                        <div className="px-3 py-1.5 bg-rose-50 text-rose-600 rounded-lg font-mono font-bold text-xs border border-rose-100 flex items-center gap-2">
                            <Clock size={14} />
                            {formatTime(timeLeft)}
                        </div>
                  )}
              </header>

              <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-12">
                  <div className="max-w-4xl mx-auto space-y-6">
                      <div className="grid grid-cols-3 gap-3 md:gap-4">
                          <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-2xl font-black text-blue-600 mb-1">{answeredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Answered</span>
                          </div>
                          <div className={`bg-white p-4 rounded-xl border shadow-sm flex flex-col items-center ${unansweredCount > 0 ? 'border-rose-100 bg-rose-50' : 'border-slate-100'}`}>
                              <span className={`text-2xl font-black mb-1 ${unansweredCount > 0 ? 'text-rose-600' : 'text-slate-900'}`}>{unansweredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Unanswered</span>
                          </div>
                          <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-2xl font-black text-rose-500 mb-1">{flaggedCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Flagged</span>
                          </div>
                      </div>

                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                          <div className="grid grid-cols-5 md:grid-cols-10 gap-2">
                              {questions.map((q, i) => (
                                  <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); setView('playing'); }}
                                    className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                        q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-700' 
                                            : 'bg-slate-50 border-slate-200 text-slate-400'
                                    }`}
                                  >
                                      {i + 1}
                                      {q.isFlagged && <Flag size={10} className="text-rose-500 absolute top-1 right-1" fill="currentColor" />}
                                  </button>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>

              <footer className="p-4 md:p-6 bg-white border-t border-slate-200 shrink-0 flex justify-between items-center">
                  <button onClick={() => setView('playing')} className="px-6 py-3 rounded-xl border-2 border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:border-slate-300">
                      Return
                  </button>
                  <button 
                    onClick={handleFinish} 
                    className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-100 flex items-center gap-2"
                  >
                      Finish <CheckCircle2 size={16} />
                  </button>
              </footer>
          </div>
      );
  }

  // --- VIEW: RESULTS ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = questions.length > 0 ? Math.round((score / questions.length) * 100) : 0;
    const mistakesCount = questions.length - score;
    const isPass = pct >= 60;

    return (
        <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar p-4 flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col my-auto shrink-0">
                <div className={`p-8 text-center relative overflow-hidden bg-slate-900`}>
                    <div className="relative z-10">
                        <div className={`w-20 h-20 mx-auto rounded-full flex items-center justify-center mb-4 shadow-xl ${isPass ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                            {isPass ? <Trophy size={32} fill="currentColor" /> : <RotateCcw size={32} />}
                        </div>
                        <h2 className="text-4xl font-black text-white font-display tracking-tight mb-1">{pct}%</h2>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">{isPass ? 'Passed' : 'Review Needed'}</p>
                    </div>
                    <div className={`absolute top-0 right-0 w-48 h-48 rounded-full blur-[60px] opacity-20 -mr-10 -mt-10 pointer-events-none ${isPass ? 'bg-emerald-400' : 'bg-rose-400'}`}></div>
                </div>

                <div className="p-6 md:p-8 space-y-6 bg-white">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="p-3 rounded-xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-xl font-black text-slate-900">{score}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Correct</span>
                        </div>
                        <div className="p-3 rounded-xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-xl font-black text-slate-900">{questions.length}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Total</span>
                        </div>
                    </div>

                    {mistakesCount > 0 && (
                        <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl flex items-start gap-3">
                            <AlertTriangle className="text-rose-500 shrink-0" size={18} />
                            <div>
                                <h4 className="font-bold text-rose-800 text-sm">Smart Review Updated</h4>
                                <p className="text-xs text-rose-600/80 mt-1">
                                    {mistakesCount} items were added to your Smart Review bank.
                                </p>
                            </div>
                        </div>
                    )}

                    <div className="space-y-3">
                        <button onClick={() => setView('review')} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-[0.15em] shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                            <BarChart3 size={16} /> Review Answers
                        </button>

                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={restartQuiz} className="py-4 bg-white border-2 border-slate-100 rounded-xl font-black uppercase text-[10px] tracking-widest text-slate-500 hover:border-slate-300 hover:text-slate-900 transition-all">
                                Retake
                            </button>
                            <button onClick={() => { if(onExit) onExit(); restartQuiz(); }} className="py-4 bg-white border-2 border-rose-100 rounded-xl font-black uppercase text-[10px] tracking-widest text-rose-500 hover:bg-rose-50 transition-all">
                                Exit
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
      return (
          <div className="h-full flex flex-col bg-slate-50">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0 sticky top-0 z-30">
                  <div className="flex items-center gap-3">
                      <button onClick={() => setView('results')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><ArrowLeft size={18}/></button>
                      <h3 className="font-black text-xs uppercase tracking-widest">Review</h3>
                  </div>
              </header>
              <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar">
                  <div className="max-w-3xl mx-auto space-y-6">
                      {questions.map((q, idx) => {
                          const isCorrect = q.userAnswer === q.correctOption;
                          return (
                              <div key={idx} className={`bg-white rounded-2xl border-2 overflow-hidden shadow-sm ${isCorrect ? 'border-emerald-100' : 'border-rose-100'}`}>
                                  <div className="p-5 md:p-6 space-y-4">
                                      <div className="flex justify-between items-start">
                                          <span className="text-[9px] font-black uppercase text-slate-400 bg-slate-50 px-2 py-1 rounded">{q.data.category.split(':')[0]}</span>
                                          {isCorrect ? <CheckCircle2 className="text-emerald-500" size={18} /> : <AlertTriangle className="text-rose-500" size={18} />}
                                      </div>

                                      {q.data.questionImage && (
                                          <div className="rounded-xl overflow-hidden border border-slate-100 bg-slate-50 flex items-center justify-center p-2 cursor-zoom-in" onClick={() => onImageClick?.(q.data.questionImage!)}>
                                              <img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 object-contain rounded-lg" alt="Review Diagram" />
                                          </div>
                                      )}

                                      <h4 className="text-base font-bold text-slate-900" dangerouslySetInnerHTML={{ __html: q.data.questionText }} />

                                      <div className="space-y-2">
                                          <div className={`p-3 rounded-lg text-xs font-bold flex items-center justify-between ${isCorrect ? 'bg-emerald-50 text-emerald-900' : 'bg-rose-50 text-rose-900'}`}>
                                              <span>Selected: {q.userAnswer || 'None'}</span>
                                              {!isCorrect && <X size={14} />}
                                          </div>
                                          {!isCorrect && (
                                              <div className="p-3 rounded-lg bg-slate-50 text-slate-900 text-xs font-bold flex items-center justify-between border border-slate-100">
                                                  <span>Correct: {q.correctOption}</span>
                                                  <Check size={14} className="text-emerald-500" />
                                              </div>
                                          )}
                                      </div>

                                      {/* Rationale in Review Mode */}
                                      <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 mt-2">
                                          <div className="flex items-center gap-2 mb-2 text-slate-400">
                                              <Info size={14} />
                                              <span className="text-[10px] font-black uppercase tracking-widest">Rationale</span>
                                          </div>
                                          <p className="text-xs text-slate-600 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: q.data.explanation || "Standard identification." }} />
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </div>
              <footer className="p-4 bg-white border-t border-slate-100">
                  <button onClick={restartQuiz} className="w-full py-3.5 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">Back to Setup</button>
              </footer>
          </div>
      );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, Volume2, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  RotateCcw, Info, Search
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

interface FlashcardsProps {
  data: Question[];
  onImageClick?: (url: string) => void;
  mistakes?: string[]; // Prop from App
  onToggleMistake?: (id: string, shouldAdd: boolean) => void; // Prop from App
  onClearMistakes?: () => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ 
    data, 
    onImageClick, 
    mistakes = [], 
    onToggleMistake, 
    onClearMistakes 
}) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [touchStart, setTouchStart] = useState<{ x: number; y: number } | null>(null);
  const [touchEnd, setTouchEnd] = useState<{ x: number; y: number } | null>(null);
  const minSwipeDistance = 50;

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakes.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    // Only sort randomly if not already persisted order (simplified for now: just random)
    if (isShuffled) {
        // Use a consistent seed if possible, but for now simple random sort
        // In a real app we'd save the shuffled ID order to localStorage
        return [...filtered].sort((a, b) => a.id.localeCompare(b.id)); // Consistent sort for now to prevent jumping
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakes, isShuffled]);

  // Handle Shuffling Persistence separately if needed, but for now:
  // If shuffle is on, we randomize once. 
  // *Correction*: To truly persist shuffle order we need to store the ID list.
  // For this scope, we will stick to consistent sorting to prevent index jumping on reload.

  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isFilterOpen) return;
      if (e.key === 'ArrowRight') {
        if (currentIndex < activeData.length - 1) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c + 1), 150);
        }
      } else if (e.key === 'ArrowLeft') {
        if (currentIndex > 0) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c - 1), 150);
        }
      } else if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        setIsFlipped(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, activeData.length, isFilterOpen, cancel]); 

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    onToggleMistake?.(id, false);
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        onClearMistakes?.();
        setShowMistakesOnly(false);
    }
  };

  useEffect(() => {
    // Safety check: index out of bounds
    if (activeData.length > 0 && currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    const distanceX = touchStart.x - touchEnd.x;
    const distanceY = touchStart.y - touchEnd.y;
    if (Math.abs(distanceX) > Math.abs(distanceY)) {
      if (distanceX > minSwipeDistance) handleNext();
      else if (distanceX < -minSwipeDistance) handlePrev();
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const getTextSizeClass = (text: string = '') => {
    const len = text.length;
    // Mobile-optimized text sizing
    if (len < 20) return 'text-3xl md:text-5xl';
    if (len < 50) return 'text-2xl md:text-4xl';
    if (len < 100) return 'text-xl md:text-3xl';
    if (len < 200) return 'text-lg md:text-2xl';
    if (len < 300) return 'text-base md:text-xl';
    return 'text-sm md:text-lg';
  };

  const formatCardText = (text: string = '') => {
    if (!text) return '';
    return text
      .replace(/^Define the term:\s*/i, '')
      .replace(/^Anatomical term for:\s*/i, '')
      .replace(/^Define:\s*/i, '')
      .replace(/^Identify the\s+/i, '')
      .trim();
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Study',
        icon: ImageIcon,
        isActive: showImagesOnly,
        onClick: () => { setShowImagesOnly(!showImagesOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-rose-50 text-rose-600 border-rose-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight font-display">
                {showMistakesOnly ? "Review Complete" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all items in your Smart Review list." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  const frontDisplayText = formatCardText(frontContent.text);
  const backDisplayText = formatCardText(backContent.text);

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-4 md:px-6 py-2 md:py-6 shrink-0 gap-3 overflow-x-auto no-scrollbar">
        <div className="flex items-center gap-2">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center shrink-0 ${selectedCategories.length > 0 || showImagesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>

           {mistakes.length > 0 && (
                <button 
                    onClick={() => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) setCurrentIndex(0); }}
                    className={`flex items-center gap-2 px-3 py-1 md:py-2 md:px-4 rounded-xl border transition-all shrink-0 ${showMistakesOnly ? 'bg-rose-100 border-rose-300 text-rose-800 shadow-sm' : 'bg-white border-slate-200 text-slate-500 hover:border-rose-200 hover:text-rose-600'}`}
                >
                    <AlertTriangle size={16} className={showMistakesOnly ? "fill-rose-500 text-rose-600" : ""} />
                    <div className="flex flex-col items-start text-[10px] uppercase font-black tracking-wider leading-none">
                        <span>Smart Review</span>
                        <span className="opacity-60 text-[9px] mt-0.5">{mistakes.length} Items</span>
                    </div>
                </button>
           )}
        </div>

        <div className="flex items-center gap-2">
           <span className="text-base md:text-lg font-black text-slate-900 font-display flex items-baseline gap-1 mr-2 hidden sm:flex">
                 {currentIndex + 1} 
                 <span className="text-xs md:text-sm font-bold text-slate-300">/ {activeData.length}</span>
           </span>

           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 shrink-0 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Shuffle Deck"
           >
             <Shuffle className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-2 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-card hover:shadow-card-hover border border-slate-100 p-6 md:p-12 flex flex-col items-center text-center group">
               <div className="w-full flex justify-between items-start mb-2 md:mb-6 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-300">
                     {frontContent.label}
                   </span>
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-1 md:py-2 space-y-4 md:space-y-6 overflow-y-auto custom-scrollbar">
                 {frontContent.image && (
                   <div 
                     className="flex-1 min-h-0 w-full flex items-center justify-center rounded-xl md:rounded-2xl p-2 md:p-4 bg-slate-50/50 border border-slate-100 relative group/img cursor-zoom-in"
                     onClick={(e) => { e.stopPropagation(); onImageClick?.(frontContent.image!); }}
                   >
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                     <div className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover/img:opacity-100 transition-opacity">
                        <Search size={14} />
                     </div>
                   </div>
                 )}

                 <h2 
                    className={`font-bold leading-tight text-slate-800 break-words w-full font-display ${getTextSizeClass(frontDisplayText)}`} 
                    dangerouslySetInnerHTML={{ __html: frontDisplayText }} 
                 />

                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 md:p-5 bg-rose-50/50 rounded-xl border border-rose-100 text-left mt-2 md:mt-4 animate-in fade-in slide-in-from-bottom-2 relative shrink-0">
                     <div className="flex items-center gap-2 mb-1 md:mb-2 text-rose-600/70">
                        <Info className="w-3 h-3 md:w-3.5 md:h-3.5" />
                        <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest">Clinical Note</span>
                     </div>
                     <p className="text-xs md:text-sm font-medium text-slate-700 leading-relaxed font-sans" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

                <button 
                    onClick={(e) => handleSpeak(e, frontDisplayText, '-front')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-slate-900 text-white rounded-full hover:bg-rose-600 shadow-xl shadow-slate-200 hover:shadow-rose-200 transition-all z-20 hover:scale-110 active:scale-95"
                >
                    {isSpeaking && speakingId?.endsWith('-front') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-white rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-white rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-white rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 className="w-[18px] h-[18px] md:w-5 md:h-5" />
                    )}
                </button>
            </div>

            {/* BACK FACE */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2rem] md:rounded-[2.5rem] shadow-premium border border-slate-800 p-6 md:p-12 flex flex-col items-center text-center group">
               <div className="w-full flex justify-between items-start mb-2 md:mb-6 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-600">
                     {backContent.label}
                   </span>
                   {mistakes.includes(currentCard.id) && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="flex items-center gap-1.5 px-3 py-1.5 bg-rose-500/20 text-rose-400 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-emerald-500/20 hover:text-emerald-400 transition-colors border border-rose-500/30 shadow-lg"
                        >
                            <CheckCircle2 size={12} /> Mastered
                        </button>
                   )}
               </div>

               <div className="flex-1 flex flex-col items-center justify-center w-full py-1 md:py-2 space-y-4 md:space-y-6 overflow-y-auto custom-scrollbar">
                 {backContent.image && (
                   <div 
                     className="flex-1 min-h-0 w-full flex items-center justify-center rounded-xl md:rounded-2xl p-2 md:p-4 bg-white/5 border border-white/10 relative group/img cursor-zoom-in"
                     onClick={(e) => { e.stopPropagation(); onImageClick?.(backContent.image!); }}
                   >
                     <img 
                       src={cleanImageUrl(backContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                     <div className="absolute top-2 right-2 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover/img:opacity-100 transition-opacity">
                        <Search size={14} />
                     </div>
                   </div>
                 )}

                 <p 
                    className={`font-bold leading-relaxed text-emerald-400 break-words w-full font-display ${getTextSizeClass(backDisplayText)}`} 
                    dangerouslySetInnerHTML={{ __html: backDisplayText }} 
                 />

                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-4 md:p-6 bg-white/5 rounded-2xl border border-white/10 text-left mt-2 md:mt-4 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <div className="flex items-center gap-2 mb-1 md:mb-2 text-slate-400">
                        <Info className="w-3 h-3 md:w-3.5 md:h-3.5" />
                        <span className="text-[9px] md:text-[10px] font-black uppercase tracking-widest">Clinical Note</span>
                     </div>
                     <p className="text-xs md:text-sm font-medium text-slate-300 leading-relaxed font-sans" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

                <button 
                    onClick={(e) => handleSpeak(e, backDisplayText, '-back')}
                    className="absolute bottom-6 right-6 md:bottom-8 md:right-8 w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-white text-slate-900 rounded-full hover:bg-emerald-400 hover:text-white shadow-xl shadow-black/20 transition-all z-20 hover:scale-110 active:scale-95"
                >
                    {isSpeaking && speakingId?.endsWith('-back') ? (
                        <div className="flex gap-0.5 items-center justify-center h-3">
                            <div className="w-0.5 h-full bg-current rounded-full animate-[pulse_0.6s_ease-in-out_infinite]"></div>
                            <div className="w-0.5 h-3/4 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.2s_infinite]"></div>
                            <div className="w-0.5 h-1/2 bg-current rounded-full animate-[pulse_0.6s_ease-in-out_0.4s_infinite]"></div>
                        </div>
                    ) : (
                        <Volume2 className="w-[18px] h-[18px] md:w-5 md:h-5" />
                    )}
                </button>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation - Bottom */}
      <div className="px-6 pb-6 pt-2 flex justify-center gap-4 md:gap-6 items-center shrink-0">
        <button onClick={handlePrev} disabled={currentIndex === 0} className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 shadow-sm active:translate-y-0.5">
          <ArrowLeft className="w-5 h-5 md:w-6 md:h-6" />
        </button>

        <button onClick={() => setIsFlipped(!isFlipped)} className="h-12 md:h-14 px-8 md:px-12 rounded-2xl bg-rose-600 flex items-center gap-3 text-white transition-all shadow-lg font-black uppercase text-[10px] md:text-xs tracking-[0.2em] group">
            <RotateCcw className={`w-4 h-4 md:w-[18px] md:h-[18px] transition-transform duration-500 ${isFlipped ? '-rotate-180' : 'rotate-0'}`} />
            Flip Card
        </button>

        <button onClick={handleNext} disabled={currentIndex === activeData.length - 1} className="w-12 h-12 md:w-14 md:h-14 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 disabled:opacity-40 shadow-sm active:translate-y-0.5">
          <ArrowRight className="w-5 h-5 md:w-6 md:h-6" />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakes.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

export default Flashcards;
